function CreateFunctionality() {
  const [inputValue, setInputValue] = useState('');
  const [createdItems, setCreatedItems] = useState([]);

  const handleCreate = () => {
    if (inputValue) {
      setCreatedItems([...createdItems, inputValue]);
      setInputValue('');
    }
  };

  return (
    <div className="bg-gray-900 p-4 rounded-lg shadow-lg">
      <h2 className="text-purple-500 text-2xl font-bold mb-4">Create Item</h2>
      <input
        type="text"
        className="bg-gray-800 text-white p-2 rounded-lg w-full mb-4"
        value={inputValue}
        onChange={(e) => setInputValue(e.target.value)}
        placeholder="Enter item name"
      />
      <Button onClick={handleCreate}>Create</Button>
      <ul className="list-none p-0 m-0 mt-4">
        {createdItems.map((item, index) => (
          <li
            key={index}
            className="bg-gray-800 p-2 rounded-lg mb-2 flex justify-between items-center"
          >
            <span className="text-white">{item}</span>
            <svg
              xmlns="http://www.w3.org/2000/svg"
              className="h-5 w-5 text-purple-500"
              viewBox="0 0 20 20"
              fill="currentColor"
            >
              <path
                fillRule="evenodd"
                d="M10 18a8 8 0 100-16 8 8 0 000 16zM7 9a1 1 0 000 2h6a1 1 0 100-2H7z"
                clipRule="evenodd"
              />
            </svg>
          </li>
        ))}
      </ul>
    </div>
  );
}

function App() {
  return (
    <div className="h-screen bg-gray-900 p-4 flex justify-center items-center">
      <CreateFunctionality />
    </div>
  );
}

